import { useQuery } from "@tanstack/react-query";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Link } from "react-router-dom";
import { ExternalLink, MapPin, Eye, EyeOff, Loader2 } from "lucide-react";
import { format } from "date-fns";
import { useState } from "react";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";

const AdminStorePublications = () => {
  const { t } = useTranslation();
  const [search, setSearch] = useState("");
  const [levelFilter, setLevelFilter] = useState<string>("all");

  const { data: stores, isLoading } = useQuery({
    queryKey: ["admin-store-publications"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("restaurants")
        .select("id, name, name_en, address, lat, lng, store_level, visible, is_draft, created_by, created_at, image_url, type")
        .not("created_by", "is", null)
        .eq("is_draft", false)
        .order("created_at", { ascending: false });

      if (error) throw error;

      // Fetch creator profiles
      const creatorIds = [...new Set((data || []).map(s => s.created_by).filter(Boolean))];
      let profiles: Record<string, { display_name: string; email?: string }> = {};
      
      if (creatorIds.length > 0) {
        const { data: profileData } = await supabase
          .from("profiles")
          .select("id, display_name")
          .in("id", creatorIds);
        
        if (profileData) {
          profileData.forEach(p => {
            profiles[p.id] = { display_name: p.display_name || "Unknown" };
          });
        }
      }

      return (data || []).map(s => ({
        ...s,
        creator_name: profiles[s.created_by!]?.display_name || "Unknown",
      }));
    },
  });

  const filtered = (stores || []).filter(s => {
    const matchesSearch = !search || 
      s.name.toLowerCase().includes(search.toLowerCase()) ||
      s.address.toLowerCase().includes(search.toLowerCase()) ||
      s.creator_name.toLowerCase().includes(search.toLowerCase());
    const matchesLevel = levelFilter === "all" || s.store_level === levelFilter;
    return matchesSearch && matchesLevel;
  });

  const levelBadge = (level: string) => {
    switch (level) {
      case "complete": return <Badge className="bg-green-500">Complete</Badge>;
      case "basic": return <Badge className="bg-blue-500">Basic</Badge>;
      case "shell": return <Badge variant="secondary">Shell</Badge>;
      default: return <Badge variant="outline">{level}</Badge>;
    }
  };

  const hasCoords = (lat: number, lng: number) => lat !== 0 || lng !== 0;

  return (
    <div className="space-y-4">
      <div>
        <h1 className="text-2xl font-bold">{t("admin.storePublications.title", "商店发布记录")}</h1>
        <p className="text-muted-foreground text-sm">{t("admin.storePublications.description", "查看所有通过「加入我们」发布的商店记录")}</p>
      </div>

      <div className="flex gap-3 flex-wrap">
        <Input
          placeholder={t("common.search", "搜索") + "..."}
          value={search}
          onChange={e => setSearch(e.target.value)}
          className="max-w-xs"
        />
        <Select value={levelFilter} onValueChange={setLevelFilter}>
          <SelectTrigger className="w-[140px]">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">{t("common.all", "全部")}</SelectItem>
            <SelectItem value="shell">Shell</SelectItem>
            <SelectItem value="basic">Basic</SelectItem>
            <SelectItem value="complete">Complete</SelectItem>
          </SelectContent>
        </Select>
        <div className="ml-auto text-sm text-muted-foreground self-center">
          {t("common.total", "共")} {filtered.length} {t("common.records", "条")}
        </div>
      </div>

      {isLoading ? (
        <div className="flex justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : (
        <div className="border rounded-lg">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>{t("admin.storePublications.storeName", "商店名称")}</TableHead>
                <TableHead>{t("admin.storePublications.address", "地址")}</TableHead>
                <TableHead>{t("admin.storePublications.level", "等级")}</TableHead>
                <TableHead>{t("admin.storePublications.coords", "经纬度")}</TableHead>
                <TableHead>{t("admin.storePublications.visible", "可见")}</TableHead>
                <TableHead>{t("admin.storePublications.creator", "发布者")}</TableHead>
                <TableHead>{t("admin.storePublications.createdAt", "发布时间")}</TableHead>
                <TableHead>{t("common.actions", "操作")}</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filtered.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={8} className="text-center text-muted-foreground py-8">
                    {t("common.noData", "暂无数据")}
                  </TableCell>
                </TableRow>
              ) : (
                filtered.map(store => (
                  <TableRow key={store.id}>
                    <TableCell className="font-medium max-w-[200px] truncate">
                      {store.name}
                    </TableCell>
                    <TableCell className="max-w-[200px] truncate text-sm text-muted-foreground">
                      {store.address}
                    </TableCell>
                    <TableCell>{levelBadge(store.store_level)}</TableCell>
                    <TableCell>
                      {hasCoords(Number(store.lat), Number(store.lng)) ? (
                        <span className="text-xs text-green-600 flex items-center gap-1">
                          <MapPin className="h-3 w-3" />
                          {Number(store.lat).toFixed(4)}, {Number(store.lng).toFixed(4)}
                        </span>
                      ) : (
                        <span className="text-xs text-destructive">⚠ 缺失</span>
                      )}
                    </TableCell>
                    <TableCell>
                      {store.visible ? (
                        <Eye className="h-4 w-4 text-green-600" />
                      ) : (
                        <EyeOff className="h-4 w-4 text-muted-foreground" />
                      )}
                    </TableCell>
                    <TableCell className="text-sm">{store.creator_name}</TableCell>
                    <TableCell className="text-sm text-muted-foreground">
                      {format(new Date(store.created_at), "yyyy-MM-dd HH:mm")}
                    </TableCell>
                    <TableCell>
                      <Button variant="ghost" size="sm" asChild>
                        <Link to={`/restaurant/${store.id}`}>
                          <Eye className="h-4 w-4" />
                        </Link>
                      </Button>
                    </TableCell>
                  </TableRow>
                ))
              )}
            </TableBody>
          </Table>
        </div>
      )}
    </div>
  );
};

export default AdminStorePublications;
